/* BTLineChart — line/area chart wrapper */

.bt-line-chart {
  width: 100%;
}

.bt-line-chart .apexcharts-tooltip {
  background: transparent !important;
  border: none !important;
  box-shadow: none !important;
  overflow: visible !important;
}

.bt-line-chart .apexcharts-xaxistooltip,
.bt-line-chart .apexcharts-yaxistooltip {
  display: none !important;
}

// Internal chart types — shared across BTBarChart, BTLineChart, BTCircleChart, BTChartCard.
// Do NOT re-export from component barrels.

/** Single bar datum for BTBarChart basic variant. */
export interface BTBarData {
  value: number;
  /** x-axis label */
  label?: string;
}

/** One rod within a grouped or stacked bar. */
export interface BTBarItem {
  value: number;
  /** CSS color or var(--token) */
  color: string;
  /** Series name shown in tooltip */
  label?: string;
}

/** One x-position group for BTBarChart grouped variant. */
export interface BTBarGroupData {
  /** x-axis label */
  label?: string;
  bars: BTBarItem[];
}

/** One stacked bar for BTBarChart stacked variant. */
export interface BTStackedBarData {
  /** x-axis label */
  label?: string;
  segments: BTBarItem[];
}

/** One (x, y) data point for BTLineChart. */
export interface BTLineSpot {
  x: number;
  y: number;
}

/** One series for BTLineChart. */
export interface BTLineSeries {
  spots: BTLineSpot[];
  /** CSS color or var(--token) */
  color: string;
  /** Series name shown in tooltip */
  label?: string;
}

/** One section for BTCircleChart. */
export interface BTCircleSection {
  value: number;
  /** CSS color or var(--token) */
  color: string;
  /** Section label shown on badge and in tooltip */
  label?: string;
}

/** Legend item shown in BTChartCard. */
export interface BTChartLegendItem {
  label: string;
  /** CSS color or var(--token) */
  color: string;
}

/** Summary metric shown in BTChartCard header area. */
export interface BTChartSummaryItem {
  label: string;
  value: string;
  unit?: string;
}

/** One row inside the chart tooltip balloon. */
export interface BTChartTooltipItem {
  /** Swatch color */
  color: string;
  /** Series name — empty string hides the label column */
  label: string;
  /** Formatted value string */
  value: string;
}

/* BTChart tooltip balloon — aligned to BTTooltip / Figma 3404:2299. */

.bt-chart-tooltip {
  display: flex;
  align-items: stretch;
  width: max-content;
  max-width: min(220px, calc(100vw - var(--space-xl)));
  color: var(--text-inverse);
  font-family: var(--typography-font-family-sans, "Geist", system-ui);
}

.bt-chart-tooltip--left {
  flex-direction: row-reverse;
}

.bt-chart-tooltip--right {
  flex-direction: row;
}

.bt-chart-tooltip--plain {
  display: block;
}

.bt-chart-tooltip__arrow-col {
  position: relative;
  width: 8px;
  align-self: stretch;
  flex-shrink: 0;
  z-index: 1;
}

.bt-chart-tooltip--left .bt-chart-tooltip__arrow-col {
  margin-left: -1px;
}

.bt-chart-tooltip--right .bt-chart-tooltip__arrow-col {
  margin-right: -1px;
}

.bt-chart-tooltip__arrow {
  position: absolute;
  top: 50%;
  display: block;
  transform: translateY(-50%);
}

.bt-chart-tooltip--left .bt-chart-tooltip__arrow {
  right: 0;
}

.bt-chart-tooltip--right .bt-chart-tooltip__arrow {
  left: 0;
}

.bt-chart-tooltip__body {
  min-width: 148px;
  padding: var(--space-lg);
  background: var(--bg-inverse);
  border-radius: var(--radius-sm);
  box-shadow: var(--shadow-elevation-xl);
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
  box-sizing: border-box;
}

.bt-chart-tooltip--plain .bt-chart-tooltip__body {
  min-width: 0;
}

.bt-chart-tooltip__title {
  margin: 0;
  color: var(--text-inverse);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  text-align: center;
}

.bt-chart-tooltip__separator {
  height: 1px;
  background: rgba(255, 255, 255, 0.2);
}

.bt-chart-tooltip__row {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
}

.bt-chart-tooltip__row + .bt-chart-tooltip__row {
  margin-block-start: var(--space-xs);
}

.bt-chart-tooltip__swatch {
  width: 12px;
  height: 12px;
  flex-shrink: 0;
  border-radius: 2px;
}

.bt-chart-tooltip__label {
  flex: 1;
  min-width: 0;
  color: var(--text-inverse);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
}

.bt-chart-tooltip__value {
  color: var(--text-inverse);
  font-size: var(--typography-font-size-sm);
  font-weight: 700;
  line-height: var(--typography-line-height-xs);
  white-space: nowrap;
}

// chart-tooltip.ts — builds the HTML string for ApexCharts custom tooltip.
// Renders a dark balloon matching Figma 3404:2299 (BTChartCard tooltip spec).

import type { BTChartTooltipItem } from './chart.types';

export interface BTChartTooltipOptions {
  placement?: 'left' | 'right' | 'none';
}

/**
 * Generates an HTML string for use in ApexCharts `tooltip.custom` callback.
 *
 * @param title  Optional headline centered at the top (e.g. "Jan", "A 40%").
 * @param items  Optional legend rows below the separator.
 * @returns HTML string ready to be returned from the ApexCharts custom function.
 */
export function buildTooltipHtml(
  title: string | null | undefined,
  items: BTChartTooltipItem[],
  options: BTChartTooltipOptions = {},
): string {
  const hasItems = items.length > 0;
  const placement = options.placement ?? 'left';
  const arrowPath = placement === 'right'
    ? 'M8 0 L1 7 Q0 8 1 9 L8 16 Z'
    : 'M0 0 L7 7 Q8 8 7 9 L0 16 Z';

  const titleHtml = title
    ? `<div class="bt-chart-tooltip__title">${escapeHtml(title)}</div>`
    : '';

  const separatorHtml =
    title && hasItems
      ? `<div class="bt-chart-tooltip__separator"></div>`
      : '';

  const rowsHtml = hasItems
    ? items
        .map(
          (item) => `
        <div class="bt-chart-tooltip__row">
          <span class="bt-chart-tooltip__swatch" style="background:${item.color}"></span>
          ${item.label ? `<span class="bt-chart-tooltip__label">${escapeHtml(item.label)}</span>` : ''}
          <span class="bt-chart-tooltip__value">${escapeHtml(item.value)}</span>
        </div>`,
        )
        .join('')
    : '';

  const bodyHtml = `
    <div class="bt-chart-tooltip__body">
      ${titleHtml}
      ${separatorHtml}
      ${rowsHtml}
    </div>
  `;

  if (placement === 'none') {
    return `<div class="bt-chart-tooltip bt-chart-tooltip--plain">${bodyHtml}</div>`;
  }

  return `
    <div class="bt-chart-tooltip bt-chart-tooltip--${placement}">
      <div class="bt-chart-tooltip__arrow-col" aria-hidden="true">
        <svg class="bt-chart-tooltip__arrow" width="8" height="16" viewBox="0 0 8 16" fill="none">
          <path d="${arrowPath}" fill="var(--bg-inverse)"></path>
        </svg>
      </div>
      ${bodyHtml}
    </div>
  `;
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

// chart-apex.utils.ts — shared ApexCharts option fragments used by all chart types.

import type { ApexOptions } from 'apexcharts';

/** Shared axis label style (10px medium, --text-secondary, Geist). */
export function btAxisLabelStyle(): object {
  return {
    fontFamily: 'var(--typography-font-family-sans, "Geist", system-ui)',
    fontSize: '10px',
    fontWeight: 500,
    colors: 'var(--text-secondary)',
  };
}

/** Shared grid options — horizontal lines only. */
export function btGridOptions(): NonNullable<ApexOptions['grid']> {
  return {
    show: true,
    borderColor: 'var(--border-primary)',
    strokeDashArray: 0,
    xaxis: { lines: { show: false } },
    yaxis: { lines: { show: true } },
    padding: { top: 0, right: 8, bottom: 0, left: 4 },
  };
}

/** Shared toolbar / zoom disable config. */
export function btChartBase(): NonNullable<ApexOptions['chart']> {
  return {
    toolbar: { show: false },
    zoom: { enabled: false },
    fontFamily: 'var(--typography-font-family-sans, "Geist", system-ui)',
    background: 'transparent',
    // Entrance animation — plays once when the chart first mounts. Bars grow
    // up from the baseline and lines/areas draw in left→right. animateGradually
    // staggers multi-series so each series eases in just after the previous.
    animations: {
      enabled: true,
      speed: 800,
      animateGradually: { enabled: true, delay: 150 },
      dynamicAnimation: { enabled: true, speed: 350 },
    },
    parentHeightOffset: 0,
  };
}

/**
 * Infer Y-axis max: round the data max up to the nearest 20.
 * Matches Flutter _inferMaxY logic.
 */
export function inferMaxY(values: number[]): number {
  const max = values.length > 0 ? Math.max(...values) : 0;
  if (max === 0) return 100;
  return Math.ceil(max / 20) * 20;
}
